queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?patios a :Patios .
    ?patios p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?verandas a :Verandas .
    ?verandas p:name ?name .
    ?verandas p:Number_of_Seats ?number_of_seats_f .
    FILTER((STR(?number_of_seats_f) = "50" || STR(?number_of_seats_f) = "50.0"))
    BIND(?name AS ?o0)
  }
}

